// App.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { motion } from 'framer-motion';
import './App.css';

const BACKEND_URL = 'http://localhost:5000/api';

function App() {
  const [seats, setSeats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState('');

  const fetchSeats = async () => {
    try {
      const response = await axios.get(`${BACKEND_URL}/seats`);
      setSeats(response.data.data);
      setLoading(false);
    } catch (error) {
      console.error("Error fetching seats:", error);
      setMessage("Error fetching seats.");
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSeats();
  }, []);

  const handleReserve = async (seat) => {
    if (seat.status !== 'available') {
      alert("Seat already reserved!");
      return;
    }
    const user_name = prompt("Please enter your name to reserve this seat:");
    if (!user_name) return;
    try {
      const response = await axios.post(`${BACKEND_URL}/reserve`, {
        seat_id: seat.id,
        user_name
      });
      setMessage(response.data.message);
      fetchSeats(); // Refresh seats after reservation
    } catch (error) {
      console.error("Error reserving seat:", error);
      setMessage("Reservation failed: " + error.response.data.error);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>Book My Seat</h1>
        {message && <p className="message">{message}</p>}
      </header>
      <main>
        {loading ? (
          <p>Loading seats...</p>
        ) : (
          <div className="seat-grid">
            {seats.map(seat => (
              <motion.div
                key={seat.id}
                className={`seat ${seat.status}`}
                whileHover={{ scale: 1.1, rotate: 2 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => handleReserve(seat)}
              >
                <h2>{seat.seat_number}</h2>
                <p>Status: {seat.status}</p>
              </motion.div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
